    metaDescription: "Sensitivity analysis for startups: identify which assumptions matter most. Learn to build tornado charts and test assumptions.",
    keywords: ["sensitivity analysis", "assumption testing", "financial modeling", "tornado chart", "key drivers"],
    image: "https://images.unsplash.com/photo-1504384308090-c894fdcc538d?w=800",
